19	/**
20	 * Maximum allowed sum of `share_percentage` across active assignments on a
21	 * single line item, plus a 1-DB-tick slack to absorb float rounding from
22	 * the rebalance planners. The DB column is `Numeric(7, 4)` so values within
23	 * [100, 100.0001) round to the same persisted total.
24	 */
25	const SHARE_SUM_LIMIT = 100.0001;
26	
27	/**
28	 * Pure check: does adding `candidate` to the active sibling shares (with
29	 * an optional `excludeId` for self-update flows) push the sum past the
30	 * allowed limit?
31	 *
32	 * Rows with `share_percentage == null` are in even-split mode and don't
33	 * contribute to the custom-share budget, so they're skipped.
34	 */
35	export function wouldExceedShareLimit(
36	  rows: readonly Pick<Assignment, 'id' | 'share_percentage'>[],
37	  candidate: number,
38	  excludeId?: string
39	): boolean {
40	  const siblingSum = rows
41	    .filter((row) => row.id !== excludeId && row.share_percentage != null)
42	    .reduce((acc, row) => acc + Number(row.share_percentage), 0);
43	  return siblingSum + candidate > SHARE_SUM_LIMIT;
44	}
