46	/**
47	 * Compose the writes needed to soft-delete an assignment and rebalance its
48	 * surviving siblings. Pure: takes the already-fetched `self` row and the
49	 * cohort (all active rows on the same line item, including `self`), returns
50	 * the writes to apply or `null` when the delete should be skipped (row
51	 * missing or already deleted).
52	 */
53	export function planAssignmentDelete(
54	  selfId: string,
55	  self: Assignment | undefined,
56	  cohort: readonly Assignment[]
57	): { siblingUpdates: SiblingShareUpdate[] } | null {
58	  if (!self || self.deleted_at != null) {
59	    return null;
60	  }
61	  const siblings = cohort.filter((row) => row.id !== selfId);
62	  const updates = planRemoveRebalance(
63	    adaptForPlanner(self),
64	    siblings.map(adaptForPlanner)
65	  );
66	  return { siblingUpdates: updates ?? [] };
