1	import { useZero } from '@rocicorp/zero/react';
2	import { mutators } from '@splitzy/shared-zero/mutators';
3	import Decimal from 'decimal.js';
4	import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
5	
6	import { mergeSeedEntries } from '@/features/assignments/utils/merge-seed-entries';
7	import {
8	  evenShares,
9	  largestRemainderRound,
10	  rebalance,
11	  type ShareEntry,
12	} from '@/features/assignments/utils/split-percent';
13	import type { ReceiptLineItem } from '@/models/ReceiptLineItem';
14	import { getUserDisplayName } from '@/utils/user-display';
15	
16	const PERSIST_DEBOUNCE_MS = 150;
17	
18	/**
19	 * React-layer view of a single share row. Extends the pure {@link ShareEntry}
20	 * with display-only fields the UI needs (display name, color lookup key).
21	 */
22	export type DraftEntry = ShareEntry & {
23	  receiptUserId: string;
24	  displayName: string;
25	};
26	
27	export type UseSplitPercentArgs = {
28	  item: ReceiptLineItem;
29	};
30	
31	export type UseSplitPercentResult = {
32	  entries: DraftEntry[];
33	  roundedPercents: number[];
34	  handleChange: (assignmentId: string, value: Decimal) => void;
35	  handleToggleLock: (assignmentId: string) => void;
36	  handleReset: () => void;
37	};
38	
39	/**
40	 * Owns the React-side orchestration for the "split by percent" tab:
41	 *
42	 *   - Seeds local draft state from the assignments coming off the receipt.
43	 *   - Re-seeds when the underlying assignments change (add/remove/remote update).
44	 *   - Debounces per-row writes back to Zero so slider drags coalesce into a
45	 *     single mutator call per row.
46	 *   - Exposes ready-to-render `entries` and `roundedPercents` plus the three
47	 *     handlers the view needs.
48	 *
49	 * All numerical work is delegated to the pure helpers in `../utils/split-percent`.
50	 */
51	export function useSplitPercent({
52	  item,
53	}: UseSplitPercentArgs): UseSplitPercentResult {
54	  const zero = useZero();
55	
56	  // Only active assignments participate in the split; soft-deleted rows would
57	  // otherwise skew the even-share fallback and show ghost rows in the UI.
58	  const activeAssignments = useMemo(
59	    () => item.assignments.filter((assignment) => !assignment.deletedAt),
60	    [item.assignments]
61	  );
62	
63	  // Build a stable key that changes whenever any assignment id, share, or
64	  // lock flag changes. Used to re-seed local state from the source of truth.
65	  const seedKey = useMemo(
66	    () =>
67	      activeAssignments
68	        .map(
69	          (assignment) =>
70	            `${assignment.id}:${assignment.sharePercentage?.toString() ?? 'null'}:${assignment.locked ? 1 : 0}`
71	        )
72	        .join('|'),
73	    [activeAssignments]
74	  );
75	
76	  // Derive the initial draft entries from the receipt's assignments. Rows
77	  // without an explicit share split the leftover percentage evenly so they
78	  // don't over-allocate when siblings already have custom shares.
79	  const seedEntries = useMemo<DraftEntry[]>(() => {
80	    let sumCustom = new Decimal(0);
81	    let nullCount = 0;
82	    for (const assignment of activeAssignments) {
83	      if (assignment.sharePercentage != null) {
84	        sumCustom = sumCustom.plus(assignment.sharePercentage);
85	      } else {
86	        nullCount += 1;
87	      }
88	    }
89	
90	    let fallbackPerNull = new Decimal(0);
91	    if (nullCount > 0) {
92	      const remaining = Decimal.max(0, new Decimal(100).minus(sumCustom));
93	      fallbackPerNull = remaining.dividedBy(nullCount);
94	    }
95	
96	    return activeAssignments.map((assignment) => {
97	      let share: Decimal;
98	      if (assignment.sharePercentage != null) {
99	        // Persisted custom share exists → honor it.
100	        share = assignment.sharePercentage;
101	      } else {
102	        // No persisted share yet → split the remaining percentage evenly
103	        // across the other null rows.
104	        share = fallbackPerNull;
105	      }
106	
107	      return {
108	        id: assignment.id,
109	        receiptUserId: assignment.receiptUserId,
110	        displayName: getUserDisplayName(assignment),
111	        share,
112	        locked: assignment.locked,
113	      };
114	    });
115	  }, [activeAssignments]);
116	
117	  const [entries, setEntries] = useState<DraftEntry[]>(seedEntries);
118	
119	  // Single in-flight debounce timer for the line item. Slider drags coalesce
120	  // into one batched `assignments.updateShares` call so the server validates
121	  // the post-state total atomically rather than per-row (which races with
122	  // sibling rebalances and trips the >100% guard).
123	  const pendingPersistRef = useRef<{
124	    timer: ReturnType<typeof setTimeout>;
125	    snapshot: DraftEntry[];
126	    pendingIds: Set<string>;
127	  } | null>(null);
128	
129	  // Re-seed whenever the upstream assignments change so remote edits and
130	  // add/remove operations are reflected locally — but preserve any row
131	  // whose persist is still pending so an echoed sync can't yank a slider
132	  // mid-drag. Gated by `seedKey` (a value, not a reference) so reference
133	  // churn from unrelated Zero updates doesn't trigger reconciliation.
134	  const lastSeededKeyRef = useRef<string | null>(null);
135	  useEffect(() => {
136	    if (lastSeededKeyRef.current === seedKey) return;
137	    lastSeededKeyRef.current = seedKey;
138	
139	    const pending = pendingPersistRef.current;
140	    if (pending) {
141	      const seedIds = new Set(seedEntries.map((entry) => entry.id));
142	      const survivingPending = new Set<string>();
143	      for (const id of pending.pendingIds) {
144	        if (seedIds.has(id)) survivingPending.add(id);
145	      }
146	      if (survivingPending.size === 0) {
147	        clearTimeout(pending.timer);
148	        pendingPersistRef.current = null;
149	      } else if (survivingPending.size !== pending.pendingIds.size) {
150	        pending.pendingIds = survivingPending;
151	        pending.snapshot = pending.snapshot.filter((entry) =>
152	          seedIds.has(entry.id)
153	        );
154	      }
155	    }
156	    const pendingIds = new Set(pendingPersistRef.current?.pendingIds ?? []);
157	    setEntries((prev) => mergeSeedEntries(prev, seedEntries, pendingIds));
158	  }, [seedKey, seedEntries]);
159	
160	  useEffect(() => {
161	    return () => {
162	      const pending = pendingPersistRef.current;
163	      if (pending) {
164	        clearTimeout(pending.timer);
165	        pendingPersistRef.current = null;
166	      }
167	    };
168	  }, []);
169	
170	  const flushBatch = useCallback(
171	    (snapshot: DraftEntry[]) => {
172	      void zero.mutate(
173	        mutators.assignments.updateShares({
174	          receipt_line_item_id: item.id,
175	          updates: snapshot.map((entry) => ({
176	            id: entry.id,
177	            share_percentage: entry.share.toDecimalPlaces(4).toNumber(),
178	          })),
179	        })
180	      );
181	      pendingPersistRef.current = null;
182	    },
183	    [zero, item.id]
184	  );
185	
186	  const scheduleBatch = useCallback(
187	    (next: DraftEntry[], changedIds: Set<string>) => {
188	      const existing = pendingPersistRef.current;
189	      if (existing) {
190	        clearTimeout(existing.timer);
191	        for (const id of existing.pendingIds) changedIds.add(id);
192	      }
193	      const pendingIds = changedIds;
194	      const timer = setTimeout(() => {
195	        const current = pendingPersistRef.current;
196	        if (!current) return;
197	        flushBatch(current.snapshot);
198	      }, PERSIST_DEBOUNCE_MS);
199	      pendingPersistRef.current = {
200	        timer,
201	        snapshot: next,
202	        pendingIds,
203	      };
204	    },
205	    [flushBatch]
206	  );
207	
208	  const handleChange = useCallback(
209	    (assignmentId: string, value: Decimal) => {
210	      setEntries((prev) => {
211	        // Delegate the math to the pure module. Any row whose share moved
212	        // joins the pending batch so the whole new state is persisted in
213	        // one atomic mutator call.
214	        const next = rebalance(prev, assignmentId, value);
215	        const changedIds = new Set<string>();
216	        for (const entry of next) {
217	          const before = prev.find((candidate) => candidate.id === entry.id);
218	          if (!before || !before.share.equals(entry.share)) {
219	            changedIds.add(entry.id);
220	          }
221	        }
222	        if (changedIds.size > 0) {
223	          scheduleBatch(next, changedIds);
224	        }
225	        return next;
226	      });
227	    },
228	    [scheduleBatch]
229	  );
230	
231	  const handleToggleLock = useCallback(
232	    (assignmentId: string) => {
233	      setEntries((prev) => {
234	        // Flip the lock flag for the targeted row only.
235	        const next = prev.map((entry) => {
236	          if (entry.id === assignmentId) {
237	            return { ...entry, locked: !entry.locked };
238	          }
239	          return entry;
240	        });
241	
242	        // Mirror the new lock state to Zero so it persists.
243	        const target = next.find((entry) => entry.id === assignmentId);
244	        if (target) {
245	          void zero.mutate(
246	            mutators.assignments.update({
247	              id: assignmentId,
248	              locked: target.locked,
249	            })
250	          );
251	        }
252	
253	        return next;
254	      });
255	    },
256	    [zero]
257	  );
258	
259	  const handleReset = useCallback(() => {
260	    setEntries((prev) => {
261	      // Reset: every row gets the even share and every lock is cleared.
262	      const share = evenShares(prev.length);
263	      const next = prev.map((entry) => ({
264	        ...entry,
265	        share,
266	        locked: false,
267	      }));
268	
269	      // Cancel any pending debounced batch so it can't clobber this reset.
270	      const pending = pendingPersistRef.current;
271	      if (pending) {
272	        clearTimeout(pending.timer);
273	        pendingPersistRef.current = null;
274	      }
275	
276	      // Single batched transaction so the post-state total is validated once
277	      // and locks/shares move atomically.
278	      const sharePercentage = share.toDecimalPlaces(4).toNumber();
279	      void zero.mutate(
280	        mutators.assignments.updateShares({
281	          receipt_line_item_id: item.id,
282	          updates: next.map((entry) => ({
283	            id: entry.id,
284	            share_percentage: sharePercentage,
285	            locked: false,
286	          })),
287	        })
288	      );
289	
290	      return next;
291	    });
292	  }, [zero, item.id]);
293	
294	  // Pre-compute the integer percents shown in the UI so the component layer
295	  // never has to deal with rounding math directly.
296	  const roundedPercents = useMemo(
297	    () => largestRemainderRound(entries.map((entry) => entry.share)),
298	    [entries]
299	  );
300	
301	  return {
302	    entries,
303	    roundedPercents,
304	    handleChange,
305	    handleToggleLock,
306	    handleReset,
307	  };
308	}
